command:
/bin/bash -lc "python3 - <<'PY'
import itertools, subprocess
verbs=['get','set','create','deploy','claim','collect','withdraw','drain','rescue','recover','sweep','skim','pool','farm','farming','token','beneficiary','owner','admin','player','solve','start','stop']
objs=['Token','Pool','Farm','Farming','Beneficiary','Owner','Admin','Player','Rewards','Reward','Challenge','PoolAddress','Factory','Implementation','Target']
forms=[]
for v in verbs:
    forms.append(v+'()')
    for o in objs:
        forms.append(v+o+'()')
        forms.append(v+o+'(address)')
        forms.append(v+o+'(uint256)')
sels={
'1f7b6d32','3df8504b','7f64ba03','0c74db12','19fc92f6','4ac0374e','4b40f6d8','535941cf','713494d7','730a8bdb','7be1623e','7cfc2995','a91ee0dc','b0539187','f0ec7e30'
}
for sig in forms:
    try:
        out=subprocess.check_output(['cast','sig',sig],text=True).strip()
    except Exception:
        continue
    if out[2:] in sels:
        print(out, sig)
PY"

