command:
/bin/bash -lc "python3 - <<'PY'
import subprocess,itertools
unknown_pool={'53e97868','67795783','6b6ec9a7','cc1f97cf','d0c93a7c','ef01df4f'}
unknown_farm={'0d5df7ba','41079fce','82bd79ea','88cb6632','96da9bd5','9555f4c3'}
verbs=['get','set','deposit','withdraw','claim','collect','harvest','swap','execute','buy','sell','sync','skim','flash','borrow','repay','stake','unstake','fund','drain','rug','solve','pwn']
objs=['','Token','Pool','Farm','Reward','Rewards','Amount','Balance','Beneficiary','Owner','Shares','Price','Rate']
args=['()','(address)','(uint256)','(address,uint256)','(uint256,address)']
for target,name in [(unknown_pool,'POOL'),(unknown_farm,'FARM')]:
    print('===',name)
    for v in verbs:
        for o in objs:
            for a in args:
                sig=f'{v}{o}{a}'
                try: sel=subprocess.check_output(['cast','sig',sig],text=True).strip()[2:]
                except: continue
                if sel in target:
