from math import floor
profits=[]
# initial total supply S, total assets T, user holds q shares
for S in range(2,80):
  for T in range(1,80):
    for q in range(1,S):
      # withdraw all q
      out=(q*T)//S
      S2=S-q
      T2=T-out
      # redeposit out
      m=(out*S2)//T2 if T2 else None
      if T2 and m>q:
        profits.append((m-q,S,T,q,out,S2,T2,m))
if profits:
  print('found',sorted(profits)[-20:])
else:
  print('no profit')
