command:
python3 - <<'PY'

def execute_withdraw(q,basis,shares_w,assets_recv,shares_ful):
    if shares_w==0 or shares_ful==0:
        return None
    s=(q*shares_ful)//shares_w
    a=(s*assets_recv)//shares_ful
    b=(basis*shares_ful)//shares_w
    return s,a,b,q-s,basis-b

for shares_w in range(1,20):
  for shares_ful in range(1,shares_w+1):
    for assets_recv in range(0,40):
      for q1 in range(0,shares_w+1):
        for q2 in range(0,shares_w-q1+1):
          # distribute basis equal to q for simplicity and then exhaustive below? maybe basis doesn't affect assets
          r1=execute_withdraw(q1,q1,shares_w,assets_recv,shares_ful)
          r2=execute_withdraw(q2,q2,shares_w,assets_recv,shares_ful)
          if r1 is None or r2 is None: continue
          tot=r1[1]+r2[1]
          rc=execute_withdraw(q1+q2,q1+q2,shares_w,assets_recv,shares_ful)
          if tot>assets_recv:
            print('exceeds epoch assets',shares_w,shares_ful,assets_recv,q1,q2,tot)
            raise SystemExit
          if tot>rc[1]:
            print('split gain assets',shares_w,shares_ful,assets_recv,q1,q2,'split',tot,'combined',rc[1])
            raise SystemExit
print('no split gain found')
PY

