const TITN_ARB = 173700000n * 10n**18n;
const TGT = 579000000n * 10n**18n;
function quote(tgt){ return tgt * TITN_ARB / TGT; }
const dep = 100n * 10n**18n;
const q = quote(dep);
const totalClaimable = q*3n;
const remaining = TITN_ARB - q;
const unclaimed = remaining - (totalClaimable - q); // if user1 claimed q before year
console.log({q: q.toString(), totalClaimable: totalClaimable.toString(), remaining: remaining.toString(), unclaimed: unclaimed.toString()});
let claimable = q;
let share = claimable * unclaimed / (totalClaimable-q);
console.log('share', share.toString());
EOF"

